import{_ as t,o as n,c as r,ag as i}from"./chunks/framework.5wcOFaQl.js";const g=JSON.parse('{"title":"Note-Taking, NPC-Building & Productivity 📝🤖💼","description":"","frontmatter":{},"headers":[],"relativePath":"skills/notes-npc-productivity.md","filePath":"skills/notes-npc-productivity.md"}'),o={name:"skills/notes-npc-productivity.md"};function a(s,e,d,l,u,p){return n(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="note-taking-npc-building-productivity-📝🤖💼" tabindex="-1">Note-Taking, NPC-Building &amp; Productivity 📝🤖💼 <a class="header-anchor" href="#note-taking-npc-building-productivity-📝🤖💼" aria-label="Permalink to &quot;Note-Taking, NPC-Building &amp; Productivity 📝🤖💼&quot;">​</a></h1><hr><h2 id="📝-note-taking" tabindex="-1">📝 Note-Taking <a class="header-anchor" href="#📝-note-taking" aria-label="Permalink to &quot;📝 Note-Taking&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>obsidian</strong></td><td>Notizen im Obsidian-Vault lesen, suchen, erstellen</td></tr></tbody></table><p><strong>Auslöser:</strong> „Such in meinen Notizen&quot;, „Erstell ne Notiz&quot;, „Obsidian&quot;</p><p>Ermöglicht Hermes den Zugriff auf deinen Obsidian-Vault. Notizen lesen, durchsuchen, neue anlegen – alles direkt aus der Session. Nützlich für: Wissensmanagement, Recherche-Dokumentation, Daily Notes.</p><hr><h2 id="🤖-opensim-npc-building" tabindex="-1">🤖 OpenSim NPC Building <a class="header-anchor" href="#🤖-opensim-npc-building" aria-label="Permalink to &quot;🤖 OpenSim NPC Building&quot;">​</a></h2><p>Skills für OpenSimulator – KI-gestützte NPCs in virtuellen Welten.</p><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>opensim-npc-building</strong></td><td>Bau-Workflows für den OpenSim NPC Bot (Ollama Bot)</td></tr><tr><td><strong>opensim-ossl-npc-bridge</strong></td><td>OSSL NPC + Hermes Agent Bridge – Realtime AI NPC</td></tr></tbody></table><p>Diese Skills sind für alle, die OpenSimulator-Welten betreiben und KI-gestützte NPCs erstellen wollen.</p><h3 id="opensim-npc-building" tabindex="-1">opensim-npc-building <a class="header-anchor" href="#opensim-npc-building" aria-label="Permalink to &quot;opensim-npc-building&quot;">​</a></h3><p><strong>Auslöser:</strong> „NPC bauen für OpenSim&quot;, „Ollama Bot&quot;</p><p>Bau-Workflows für den OpenSim NPC Bot. Nutzt Ollama für lokale KI und GridClient für die Steuerung im OpenSim.</p><h3 id="opensim-ossl-npc-bridge" tabindex="-1">opensim-ossl-npc-bridge <a class="header-anchor" href="#opensim-ossl-npc-bridge" aria-label="Permalink to &quot;opensim-ossl-npc-bridge&quot;">​</a></h3><p><strong>Auslöser:</strong> „Echtzeit-NPC in OpenSim&quot;, „OSSL + Hermes&quot;</p><p>Brücke zwischen OpenSims OSSL-Skriptsprache und Hermes Agent. Ermöglicht NPCs, die in Echtzeit mit Hermes&#39; KI kommunizieren – für dynamische Dialoge und reaktives Verhalten.</p><hr><h2 id="💼-productivity" tabindex="-1">💼 Productivity <a class="header-anchor" href="#💼-productivity" aria-label="Permalink to &quot;💼 Productivity&quot;">​</a></h2><p>Dokumente, Präsentationen, Termine, E-Mails und mehr.</p><table tabindex="0"><thead><tr><th>Skill</th><th>Beschreibung</th></tr></thead><tbody><tr><td><strong>airtable</strong></td><td>Airtable REST API via curl. CRUD, Filter, Upserts</td></tr><tr><td><strong>google-workspace</strong></td><td>Gmail, Kalender, Drive, Docs, Sheets via gws CLI oder Python</td></tr><tr><td><strong>linear</strong></td><td>Linear: Issues, Projekte, Teams via GraphQL + curl</td></tr><tr><td><strong>maps</strong></td><td>Geocoding, POIs, Routen, Zeitzonen via OpenStreetMap/OSRM</td></tr><tr><td><strong>nano-pdf</strong></td><td>PDF-Text/Tippfehler/Titel editieren via nano-pdf CLI</td></tr><tr><td><strong>notion</strong></td><td>Notion API via curl: Pages, Databases, Blocks, Search</td></tr><tr><td><strong>ocr-and-documents</strong></td><td>Text aus PDFs/Scans extrahieren (pymupdf, marker-pdf)</td></tr><tr><td><strong>powerpoint</strong></td><td>.pptx-Präsentationen erstellen, lesen, bearbeiten</td></tr></tbody></table><h3 id="google-workspace" tabindex="-1">google-workspace <a class="header-anchor" href="#google-workspace" aria-label="Permalink to &quot;google-workspace&quot;">​</a></h3><p><strong>Auslöser:</strong> „Schreib ne Mail&quot;, „Termin im Kalender&quot;, „Google Doc lesen&quot;</p><p>Vollständige Integration mit Google Workspace: Mails senden/lesen via Gmail, Termine verwalten im Kalender, Dokumente bearbeiten in Docs/Sheets.</p><h3 id="notion" tabindex="-1">notion <a class="header-anchor" href="#notion" aria-label="Permalink to &quot;notion&quot;">​</a></h3><p><strong>Auslöser:</strong> „Notion-Seite lesen&quot;, „Datenbank in Notion&quot;, „Eintrag erstellen&quot;</p><p>Steuert Notion via REST API: Pages lesen/schreiben, Datenbanken abfragen, Blöcke manipulieren, suchen.</p><h3 id="ocr-and-documents" tabindex="-1">ocr-and-documents <a class="header-anchor" href="#ocr-and-documents" aria-label="Permalink to &quot;ocr-and-documents&quot;">​</a></h3><p><strong>Auslöser:</strong> „Scan einscannen&quot;, „PDF als Text&quot;, „Dokument auslesen&quot;</p><p>Extrahiert Text aus PDFs und Bildern via pymupdf und marker-pdf. Erkennt Tabellen, Layouts und Strukturen.</p><h3 id="nano-pdf" tabindex="-1">nano-pdf <a class="header-anchor" href="#nano-pdf" aria-label="Permalink to &quot;nano-pdf&quot;">​</a></h3><p><strong>Auslöser:</strong> „PDF-Tippfehler korrigieren&quot;, „PDF-Titel ändern&quot;</p><p>Erlaubt gezielte Text-Änderungen in PDFs – Tippfehler korrigieren, Titel ändern, Texte ersetzen – ohne die PDF neu zu generieren.</p>',33)])])}const h=t(o,[["render",a]]);export{g as __pageData,h as default};
